const allJobs = [];
for (const item of $input.all()) {
  const d = item.json;
  if (d.error) continue;
  if ('job-count' in d && d.jobs) {
    for (const j of d.jobs) {
      allJobs.push({
        title: j.title || '',
        company: j.company_name || '',
        location: j.candidate_required_location || 'Remote',
        url: j.url || '',
        desc: (j.description || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').substring(0, 500),
        type: j.job_type || '',
        salary: j.salary || '',
        source: 'Remotive',
        date: j.publication_date || '',
        cat: j.category || '',
        tags: (j.tags || []).join(', ')
      });
    }
  } else if (d.jobs && d.jobs[0] && d.jobs[0].jobTitle) {
    for (const j of d.jobs) {
      const salary = j.annualSalaryMin ? (j.annualSalaryMin + '-' + j.annualSalaryMax) : '';
      allJobs.push({
        title: j.jobTitle || '',
        company: j.companyName || '',
        location: j.jobGeo || 'Remote',
        url: j.url || '',
        desc: (j.jobExcerpt || '').replace(/<[^>]+>/g, ' ').substring(0, 500),
        type: Array.isArray(j.jobType) ? j.jobType.join(', ') : '',
        salary: salary,
        source: 'Jobicy',
        date: j.pubDate || '',
        cat: Array.isArray(j.jobIndustry) ? j.jobIndustry.join(', ') : '',
        tags: ''
      });
    }
  } else if (Array.isArray(d.resultats)) {
    for (const j of d.resultats) {
      const company = (j.entreprise && j.entreprise.nom) || '';
      const loc = (j.lieuTravail && j.lieuTravail.libelle) || 'France';
      const url = (j.origineOffre && j.origineOffre.urlOrigine) || ('https://candidat.francetravail.fr/offres/recherche/detail/' + (j.id || ''));
      const salary = (j.salaire && j.salaire.libelle) || '';
      allJobs.push({
        title: j.intitule || '',
        company: company,
        location: loc,
        url: url,
        desc: (j.description || '').replace(/\s+/g, ' ').substring(0, 500),
        type: j.typeContratLibelle || '',
        salary: salary,
        source: 'FranceTravail',
        date: j.dateCreation || '',
        cat: j.romeLibelle || j.romeCode || '',
        tags: ''
      });
    }
  } else if (d.title && d.link) {
    const p = (d.title || '').split(':');
    allJobs.push({
      title: p.length > 1 ? p.slice(1).join(':').trim() : d.title,
      company: p[0] ? p[0].trim() : '',
      location: d.region || d.country || 'Remote',
      url: d.link || '',
      desc: (d.content || d.description || '').replace(/<[^>]+>/g, ' ').substring(0, 500),
      type: 'Full-Time',
      salary: '',
      source: 'WWR',
      date: d.pubDate || d.isoDate || '',
      cat: 'Sales',
      tags: ''
    });
  } else if ('totalCount' in d && Array.isArray(d.jobs)) {
    for (const j of d.jobs) {
      const locs = Array.isArray(j.locationRestrictions) ? j.locationRestrictions : [];
      const loc = locs.length ? locs.join(', ') : 'Remote';
      const sal = (j.minSalary && j.minSalary !== 'None') ? (j.minSalary + '-' + (j.maxSalary || '') + ' ' + (j.currency || '')) : '';
      allJobs.push({
        title: j.title || '', company: j.companyName || '', location: loc,
        url: j.applicationLink || '',
        desc: (j.description || j.excerpt || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').substring(0, 500),
        type: j.employmentType || '', salary: sal, source: 'Himalayas',
        date: j.pubDate ? new Date(Number(j.pubDate) * 1000).toISOString() : '',
        cat: Array.isArray(j.categories) ? j.categories.join(', ') : '', tags: ''
      });
    }
  } else if (Array.isArray(d.results)) {
    for (const j of d.results) {
      const loc = (j.locations && j.locations[0] && j.locations[0].name) || 'Remote';
      allJobs.push({
        title: j.name || '', company: (j.company && j.company.name) || '', location: loc,
        url: (j.refs && j.refs.landing_page) || '',
        desc: (j.contents || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').substring(0, 500),
        type: j.type || '', salary: '', source: 'TheMuse',
        date: j.publication_date || '',
        cat: Array.isArray(j.categories) ? j.categories.map(c => c.name).join(', ') : '', tags: ''
      });
    }
  } else if (d.position && (d.url || d.apply_url) && !d.legal) {
    allJobs.push({
      title: d.position || '', company: d.company || '', location: d.location || 'Remote',
      url: d.url || d.apply_url || '',
      desc: (d.description || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').substring(0, 500),
      type: '', salary: (d.salary_min && String(d.salary_min) !== '0') ? (d.salary_min + '-' + d.salary_max) : '',
      source: 'RemoteOK', date: d.date || '', cat: '',
      tags: Array.isArray(d.tags) ? d.tags.join(', ') : ''
    });
  }
}

const INCLUDE = ["account executive", "enterprise account executive", "strategic account executive", "mid-market account executive", "smb account executive", "account manager", "key account manager", "named account manager", "strategic account manager", "account director", "account management", "revenue operations", "revops", "rev ops", "sales operations", "sales ops", "gtm operations", "gtm ops", "go-to-market operations", "growth operations", "growth ops", "outbound sales", "outbound operations", "business development", "business developer", "partnerships", "partner manager", "alliances", "customer success manager", "sales manager", "ingenieur d'affaires", "charge d'affaires", "charge de developpement commercial", "responsable grands comptes", "responsable comptes cles", "gestionnaire grands comptes"];
const EXCLUDE = ["head of sales", "vp sales", "vp of sales", "vice president of sales", "svp sales", "chief revenue officer", "chief sales officer", "directeur commercial", "directrice commerciale", "directeur des ventes", "sales director", "technico-commercial", "technico commercial", "commercial terrain", "commercial sedentaire", "commercial itinerant", "vendeur", "vendeuse", "televente", "teleconseiller", "teleprospecteur", "porte-a-porte", "vrp", "agent commercial", "agent general", "assurance", "assureur", "mutuelle", "prevoyance", "courtier", "immobilier", "btp", "batiment", "menuiserie", "fenetre", "isolation", "photovoltaique", "panneaux solaires", "automobile", "concession", "grande distribution", "pompes funebres", "sales engineer", "sales engineering", "presales", "pre-sales", "avant-vente", "sales development", "sdr", "salesforce", "recruteur", "recruitment", "talent acquisition", "stage", "alternance", "apprentissage", "stagiaire"];
const L = ["remote", "fully remote", "full remote", "remote-first", "remote france", "remote europe", "eu remote", "wfh", "work from home", "distributed", "anywhere", "worldwide", "teletravail", "distanciel", "hybrid", "hybride", "france", "nantes", "toulouse", "lyon", "paris", "bordeaux", "lille", "rennes", "nice", "montpellier", "marseille", "strasbourg", "nouvelle-aquitaine", "ile-de-france", "europe", "emea", "global"];
const VAGUE_LOC = ['', 'unknown', 'not specified', 'n/a', 'na', 'none', '?', '-'];
const deburr = s => (s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const filtered = (typeof allJobs !== 'undefined' ? allJobs : jobs).filter(j => {
  const title = deburr(j.title);
  const hay = deburr((j.title || '') + ' ' + (j.desc || ''));
  if (EXCLUDE.some(k => title.indexOf(k) >= 0)) return false;
  const roleMatch = INCLUDE.some(k => title.indexOf(k) >= 0);
  const loc = deburr(j.location).trim();
  const locationMatch = L.some(k => loc.indexOf(k) >= 0) || VAGUE_LOC.indexOf(loc) >= 0;
  return roleMatch && locationMatch;
});

const seen = new Set();
const unique = filtered.filter(j => {
  const k = (j.title + '_' + j.company).toLowerCase();
  if (seen.has(k)) return false;
  seen.add(k);
  return true;
});

unique.sort((a, b) => new Date(b.date || 0) - new Date(a.date || 0));
return unique.map(j => ({ json: j }));

const items = $input.all().map(i => i.json);

if (items.length === 1 && items[0]._no_new_jobs) {
  return [{ json: {
    _no_new_jobs: true,
    _stats: items[0]._stats || {},
    jobs: [],
    jobsCount: 0,
    requestBody: {
      model: $env.VEILLE_SCORE_MODEL_LOCAL,
      messages: [
        { role: 'system', content: 'Reply only with JSON.' },
        { role: 'user', content: 'Output exactly: {"scores":[]}' }
      ],
      stream: false,
      format: 'json',
      options: { temperature: 0 }
    }
  } }];
}

const MAX = parseInt($env.VEILLE_BATCH_MAX, 10) || 40;
const batch = items.slice(0, MAX);

let jobsText = '';
for (let i = 0; i < batch.length; i++) {
  const j = batch[i];
  jobsText += (i+1) + '. ' + j.title + ' @ ' + j.company + ' (' + j.location + ')\n';
  jobsText += 'Source: ' + j.source + ' | URL: ' + j.url + '\n';
  jobsText += 'Desc: ' + (j.desc || '').substring(0, 300) + '\n';
  jobsText += 'Match CV (0-1): ' + (typeof j._cv_score === 'number' ? j._cv_score.toFixed(2) : 'n/a') + '\n\n';
}

const sys = 'Tu es un assistant de veille emploi pour un candidat base a Bordeaux (France), qui recherche surtout du REMOTE. Profil cible: Account Executive, Account Manager / Key Account, Revenue Operations, Sales Ops, GTM Ops, Outbound/Growth Ops, Business Development. Secteurs prioritaires: crypto/web3/fintech, foodtech, AI/ML, SaaS. NON cible (score bas): postes trop seniors (Head of Sales, VP, Director, CRO), technico-commercial, assurance, immobilier, BTP, vente terrain. Un champ Match CV (0-1) est fourni par offre: plus il est eleve, plus l adequation au profil du candidat est forte; pondere le score en consequence. Reponds UNIQUEMENT en JSON valide.';

const usr = 'Voici ' + batch.length + ' offres.\n\nRegles de scoring:\n- 8-10: secteur prioritaire (crypto/fintech/food/AI) ET role commercial senior ET location France ou remote EMEA\n- 5-7: 2 criteres sur 3 OK\n- 0-4: hors scope (role technique/junior, secteur non prioritaire, location non accessible)\n\nIMPORTANT: la raison doit etre SPECIFIQUE a l offre (mentionne le nom de l entreprise ou le produit ou un point concret du poste). INTERDIT: raisons generiques repetees comme "Data et AI, DevSecOps". Max 15 mots.\n\nFormat: { "scores": [ { "n": 1, "score": 8, "class": "top", "reason": "..." } ] }\nclass: top si >=7, watch si 4-6, skip si <4.\n\nOffres:\n' + jobsText;

const msgs = [
  { role: 'system', content: sys },
  { role: 'user', content: usr }
];

const opts = { temperature: 0.3 };
const requestBody = { model: $env.VEILLE_SCORE_MODEL_LOCAL, messages: msgs, stream: false, format: 'json', options: opts };

const out = { requestBody: requestBody, jobs: batch, jobsCount: batch.length };
return [{ json: out }];

const llm = $input.first().json;
const preparedJson = $('Prepare Scoring').first().json || {};
const preparedJobs = preparedJson.jobs || [];
const noNew = !!preparedJson._no_new_jobs;
const stats = preparedJson._stats || {};

const today = new Date().toISOString().substring(0, 10);
const TO_EMAIL = $env.VEILLE_TO_EMAIL;

function esc(s) {
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}
function fmtCv(j) {
  if (j._cv_score === undefined || j._cv_score === null) return '';
  return ' | CV ' + j._cv_score.toFixed(2);
}
function htmlShell(title, bodyInner) {
  return '<!doctype html><html><body style="margin:0;padding:0;background:#f6f7f9;font-family:-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;color:#1f2328;">'
    + '<div style="max-width:680px;margin:0 auto;padding:24px;">'
    + '<h1 style="font-size:20px;margin:0 0 16px;">' + title + '</h1>'
    + bodyInner
    + '<hr style="border:0;border-top:1px solid #e1e4e8;margin:24px 0;">'
    + '<div style="font-size:12px;color:#6a737d;">Veille Emploi · self-hosted-ai-starter-kit · ' + esc(today) + '</div>'
    + '</div></body></html>';
}
function jobCard(j) {
  const score = j.score || 0;
  const cv = (j._cv_score != null) ? j._cv_score.toFixed(2) : null;
  const badge = '<span style="display:inline-block;background:#0969da;color:#fff;border-radius:4px;padding:2px 8px;font-size:12px;font-weight:600;">' + score + '/10</span>';
  const cvBadge = cv ? ' <span style="display:inline-block;background:#ddf4ff;color:#0969da;border-radius:4px;padding:2px 8px;font-size:12px;">CV ' + esc(cv) + '</span>' : '';
  let cvTop = '';
  if (j._cv_top && j._cv_top.length > 0) {
    const sec = j._cv_top.map(t => esc(t.section) + ' (' + t.score.toFixed(2) + ')').join(', ');
    cvTop = '<div style="font-size:12px;color:#6a737d;margin-top:4px;">CV match: ' + sec + '</div>';
  }
  return '<div style="border:1px solid #e1e4e8;border-radius:8px;padding:16px;margin-bottom:12px;background:#fff;">'
    + '<div style="margin-bottom:8px;">' + badge + cvBadge + '</div>'
    + '<div style="font-size:16px;font-weight:600;margin-bottom:4px;">' + esc(j.title) + '</div>'
    + '<div style="font-size:14px;color:#57606a;margin-bottom:8px;">' + esc(j.company) + ' · ' + esc(j.location) + ' · <span style="color:#8b949e;">' + esc(j.source) + '</span></div>'
    + '<div style="font-size:13px;color:#24292f;margin-bottom:10px;"><em>' + esc(j.reason) + '</em></div>'
    + (j.salary ? '<div style="font-size:13px;margin-bottom:8px;">Salary: ' + esc(j.salary) + '</div>' : '')
    + cvTop
    + '<a href="' + esc(j.url) + '" style="display:inline-block;margin-top:10px;background:#1f883d;color:#fff;padding:6px 14px;border-radius:6px;text-decoration:none;font-size:13px;font-weight:500;">Voir l offre &rarr;</a>'
    + '</div>';
}
function watchLine(j) {
  const cv = (j._cv_score != null) ? ' · CV ' + j._cv_score.toFixed(2) : '';
  return '<li style="margin-bottom:6px;font-size:13px;">'
    + '<strong>' + (j.score || 0) + '/10</strong>' + cv + ' · '
    + '<a href="' + esc(j.url) + '" style="color:#0969da;text-decoration:none;">' + esc(j.title) + '</a> '
    + '<span style="color:#57606a;">@ ' + esc(j.company) + ' — ' + esc(j.location) + '</span> '
    + '<em style="color:#6a737d;">' + esc(j.reason) + '</em>'
    + '</li>';
}

function buildOutput(payload) {
  const filePath = $env.VEILLE_OUTPUT_DIR + '/jobs/' + today + '.md';
  const base64 = Buffer.from(payload.md, 'utf-8').toString('base64');
  const binaryData = { data: base64, mimeType: 'text/markdown', fileName: today + '.md', fileExtension: 'md' };
  return [{
    json: {
      filePath: filePath,
      count: payload.count,
      topCount: payload.topCount,
      watchCount: payload.watchCount,
      mode: payload.mode,
      errorMsg: payload.errorMsg || '',
      subject: payload.subject,
      html: payload.html,
      to: TO_EMAIL,
      stats: stats
    },
    binary: { data: binaryData }
  }];
}

if (noNew) {
  let md = '# Veille Emploi — ' + today + '\n\n';
  md += '_Aucune nouvelle offre — toutes les offres collectees etaient deja indexees._\n\n';
  md += '## Stats collecte\n\n';
  md += '- Collectees apres normalisation: ' + (stats.input || 0) + '\n';
  md += '- Deja vues (dedup): ' + (stats.existing || 0) + '\n';
  md += '- Embed echec: ' + (stats.embedFailed || 0) + '\n';
  const subject = '[Veille Emploi] ' + today + ' — 0 nouvelle offre';
  const inner = '<p style="font-size:14px;color:#57606a;">Aucune nouvelle offre — toutes les offres collectees etaient deja indexees.</p>'
    + '<h3 style="font-size:14px;margin-top:24px;">Stats collecte</h3>'
    + '<ul style="font-size:13px;color:#24292f;"><li>Collectees: ' + (stats.input || 0) + '</li>'
    + '<li>Deja vues (dedup): ' + (stats.existing || 0) + '</li>'
    + '<li>Embed echec: ' + (stats.embedFailed || 0) + '</li></ul>';
  return buildOutput({ md, count: 0, topCount: 0, watchCount: 0, mode: 'NO_NEW', subject, html: htmlShell('Veille Emploi — ' + today, inner) });
}

let mode = 'OK';
let errorMsg = '';
let scores = [];
const llmError = llm && llm.error;
const content = llm && llm.message && llm.message.content ? llm.message.content : '';

if (llmError) {
  mode = 'FAILED';
  errorMsg = (llmError.message || llmError.code || 'unknown error');
} else if (!content) {
  mode = 'DEGRADED';
  errorMsg = 'LLM returned empty content';
} else {
  try {
    const parsed = typeof content === 'string' ? JSON.parse(content) : content;
    scores = parsed.scores || [];
    if (!Array.isArray(scores) || scores.length === 0) {
      mode = 'DEGRADED';
      errorMsg = 'LLM output parsed but contained no scores';
    }
  } catch (e) {
    mode = 'DEGRADED';
    errorMsg = 'JSON parse failed: ' + e.message;
  }
}

const scored = preparedJobs.map((j, i) => {
  const found = scores.find(x => Number(x.n) === (i+1));
  const score = found ? (found.score || 0) : 0;
  const klass = found ? (found.class || 'skip') : 'skip';
  const reason = found ? (found.reason || '') : 'non score';
  return Object.assign({}, j, { score: score, klass: klass, reason: reason });
});

function sortByScore(a, b) {
  if (b.score !== a.score) return b.score - a.score;
  return (b._cv_score || 0) - (a._cv_score || 0);
}

const top = scored.filter(j => j.klass === 'top').sort(sortByScore);
const watch = scored.filter(j => j.klass === 'watch').sort(sortByScore);

let md = '# Veille Emploi — ' + today + '\n\n';
let inner = '';
let subject = '';

if (mode !== 'OK') {
  md += '> Pipeline ' + mode + ' — ' + errorMsg + '\n';
  md += '> ' + preparedJobs.length + ' offres collectees, scoring indisponible.\n\n';
  md += '## Offres collectees (brut, non scorees)\n\n';
  for (const j of preparedJobs) {
    md += '- [' + (j.title || 'sans titre') + '](' + (j.url || '') + ') @ ' + (j.company || '?') + ' — ' + (j.location || '?') + ' _(source: ' + (j.source || '?') + fmtCv(j) + ')_\n';
  }
  subject = '[Veille Emploi] ' + today + ' — PIPELINE ' + mode + ' (' + preparedJobs.length + ' offres brutes)';
  inner = '<div style="background:#ffebe9;border:1px solid #ff8182;border-radius:6px;padding:12px;margin-bottom:16px;">'
    + '<strong style="color:#d1242f;">Pipeline ' + mode + '</strong><br>'
    + '<span style="font-size:13px;color:#57606a;">' + esc(errorMsg) + '</span><br>'
    + '<span style="font-size:13px;color:#57606a;">' + preparedJobs.length + ' offres collectees, scoring indisponible.</span>'
    + '</div>';
  inner += '<h3 style="font-size:14px;">Offres collectees (brut)</h3><ul style="font-size:13px;">';
  for (const j of preparedJobs) {
    inner += '<li style="margin-bottom:4px;"><a href="' + esc(j.url) + '" style="color:#0969da;text-decoration:none;">' + esc(j.title || 'sans titre') + '</a> @ ' + esc(j.company || '?') + ' — ' + esc(j.location || '?') + ' <span style="color:#8b949e;">(' + esc(j.source || '?') + ')</span></li>';
  }
  inner += '</ul>';
} else {
  md += '_' + scored.length + ' nouvelles offres analysees — ' + top.length + ' top, ' + watch.length + ' a suivre_\n\n';
  md += '## Top (score >= 7)\n\n';
  if (top.length === 0) md += '_Aucune offre top aujourd hui._\n\n';
  for (const j of top) {
    md += '### [' + j.score + '/10' + fmtCv(j) + '] ' + j.title + ' — ' + j.company + '\n';
    md += '- Location: ' + j.location + '\n';
    md += '- Source: ' + j.source + '\n';
    md += '- URL: ' + j.url + '\n';
    md += '- Raison: ' + j.reason + '\n';
    if (j._cv_top && j._cv_top.length > 0) {
      const topSec = j._cv_top.map(t => t.section + ' (' + t.score.toFixed(2) + ')').join(', ');
      md += '- CV match: ' + topSec + '\n';
    }
    if (j.salary) md += '- Salary: ' + j.salary + '\n';
    md += '\n';
  }
  md += '## A suivre (4-6)\n\n';
  if (watch.length === 0) md += '_Aucune offre a suivre._\n\n';
  for (const j of watch) {
    md += '- [' + j.score + '/10' + fmtCv(j) + '] [' + j.title + '](' + j.url + ') @ ' + j.company + ' — ' + j.location + ' — _' + j.reason + '_\n';
  }

  if (top.length === 0 && watch.length === 0) {
    subject = '[Veille Emploi] ' + today + ' — ' + scored.length + ' offres analysees, aucune retenue';
  } else if (top.length === 0) {
    subject = '[Veille Emploi] ' + today + ' — ' + watch.length + ' a suivre (pas de top)';
  } else {
    subject = '[Veille Emploi] ' + today + ' — ' + top.length + ' top + ' + watch.length + ' a suivre';
  }

  inner = '<div style="font-size:13px;color:#57606a;margin-bottom:16px;">' + scored.length + ' nouvelles offres analysees — <strong>' + top.length + ' top</strong>, ' + watch.length + ' a suivre</div>';
  inner += '<h2 style="font-size:16px;margin:24px 0 12px;">Top (score &ge; 7)</h2>';
  if (top.length === 0) {
    inner += '<p style="font-size:13px;color:#6a737d;"><em>Aucune offre top aujourd hui.</em></p>';
  } else {
    for (const j of top) inner += jobCard(j);
  }
  inner += '<h2 style="font-size:16px;margin:24px 0 12px;">A suivre (4-6)</h2>';
  if (watch.length === 0) {
    inner += '<p style="font-size:13px;color:#6a737d;"><em>Aucune offre a suivre.</em></p>';
  } else {
    inner += '<ul style="padding-left:20px;">';
    for (const j of watch) inner += watchLine(j);
    inner += '</ul>';
  }
}

return buildOutput({
  md,
  count: scored.length,
  topCount: top.length,
  watchCount: watch.length,
  mode,
  errorMsg,
  subject,
  html: htmlShell('Veille Emploi — ' + today, inner)
});

const items = $input.all().map(i => i.json);
const QDRANT = $env.QDRANT_URL;
const OLLAMA = $env.OLLAMA_LOCAL_URL;
const COLL = 'job_listings';
const EMBED_MODEL = $env.VEILLE_EMBED_MODEL;

function urlToId(url) {
  let hash = 14695981039346656037n;
  for (let i = 0; i < url.length; i++) {
    hash ^= BigInt(url.charCodeAt(i));
    hash = (hash * 1099511628211n) & 0x1FFFFFFFFFFFFFn;
  }
  return Number(hash);
}

// Probe helpers availability
const helpersInfo = {
  hasDollarHelpers: typeof $helpers !== 'undefined',
  hasThisHelpers: typeof this !== 'undefined' && this && typeof this.helpers !== 'undefined',
};

async function httpJSON(opts) {
  if (typeof $helpers !== 'undefined' && $helpers.httpRequest) return $helpers.httpRequest(opts);
  if (typeof this !== 'undefined' && this && this.helpers && this.helpers.httpRequest) return this.helpers.httpRequest(opts);
  throw new Error('no http helper available');
}

const newItems = [];
const upsertPoints = [];
let stats = { input: items.length, existing: 0, embedded: 0, embedFailed: 0, indexed: 0, lastScrollErr: '', lastEmbedErr: '', lastUpsertErr: '', helpersInfo: helpersInfo };

for (const it of items) {
  if (!it || !it.url) continue;

  const id = urlToId(it.url);
  let exists = false;
  try {
    const r = await httpJSON({
      method: 'POST',
      url: QDRANT + '/collections/' + COLL + '/points/scroll',
      body: { filter: { must: [{ key: 'url', match: { value: it.url } }] }, limit: 1, with_payload: false, with_vector: false },
      json: true
    });
    exists = (r && r.result && Array.isArray(r.result.points) && r.result.points.length > 0);
  } catch (e) {
    stats.lastScrollErr = (e && e.message) || String(e);
    exists = false;
  }
  if (exists) { stats.existing++; continue; }

  const text = (it.title || '') + ' chez ' + (it.company || '') + ' a ' + (it.location || '') + '. ' + (it.desc || '');
  let embedding = null;
  try {
    const er = await httpJSON({
      method: 'POST',
      url: OLLAMA + '/api/embeddings',
      body: { model: EMBED_MODEL, prompt: text.substring(0, 2000) },
      json: true,
      timeout: 60000
    });
    embedding = er && er.embedding;
  } catch (e) {
    stats.embedFailed++;
    stats.lastEmbedErr = (e && e.message) || String(e);
    continue;
  }
  if (!embedding || embedding.length !== 1024) {
    stats.embedFailed++;
    stats.lastEmbedErr = 'embedding shape invalid: len=' + (embedding ? embedding.length : 'null');
    continue;
  }
  stats.embedded++;

  const today = new Date().toISOString().substring(0, 10);
  upsertPoints.push({
    id: id,
    vector: embedding,
    payload: {
      url: it.url,
      title: it.title || '',
      company: it.company || '',
      source: it.source || '',
      location: it.location || '',
      date_collected: today
    }
  });

  newItems.push(Object.assign({}, it, { _embedding: embedding, _qdrant_id: id }));
}

// Upsert DEFERRED to post-send 'Index New Jobs' node (idempotency: mark seen ONLY after successful email delivery).
stats.indexed = -1; // -1 = deferred to post-send

if (newItems.length === 0) {
  return [{ json: { _no_new_jobs: true, _stats: stats } }];
}

return newItems.map(j => ({ json: Object.assign({}, j, { _stats: stats }) }));

const QDRANT = $env.QDRANT_URL;
const COLL = 'cv_profile';
const items = $input.all().map(i => i.json);

if (items.length === 1 && items[0]._no_new_jobs) {
  return [{ json: items[0] }];
}

const out = [];
for (const it of items) {
  if (!it._embedding) {
    out.push({ json: it });
    continue;
  }
  let cv_score = 0;
  let cv_top = [];
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: QDRANT + '/collections/' + COLL + '/points/search',
      body: { vector: it._embedding, limit: 3, with_payload: true },
      json: true
    });
    const points = (r && r.result) || [];
    if (points.length > 0) {
      cv_score = points.reduce((a, p) => a + (p.score || 0), 0) / points.length;
      cv_top = points.map(p => ({
        section: ((p.payload || {}).metadata || {}).section || '?',
        score: p.score
      }));
    }
  } catch (e) {
    // best-effort, leave cv_score at 0
  }
  const passed = Object.assign({}, it, { _cv_score: cv_score, _cv_top: cv_top });
  delete passed._embedding;
  out.push({ json: passed });
}

return out;

const QDRANT = $env.QDRANT_URL;
const COLL = 'job_listings';
let src;
try {
  src = $('Dedup + Embed').all().map(i => i.json);
} catch (e) {
  return [{ json: { _indexed: 0, _index_error: 'cannot read Dedup + Embed: ' + String(e && e.message || e) } }];
}
const today = new Date().toISOString().substring(0, 10);
const points = [];
for (const it of src) {
  if (!it || it._no_new_jobs) continue;
  if (!Array.isArray(it._embedding) || it._embedding.length !== 1024 || !it._qdrant_id) continue;
  points.push({
    id: it._qdrant_id,
    vector: it._embedding,
    payload: { url: it.url, title: it.title || '', company: it.company || '', source: it.source || '', location: it.location || '', date_collected: today }
  });
}
if (points.length === 0) return [{ json: { _indexed: 0, _note: 'no new points to index' } }];
try {
  await this.helpers.httpRequest({ method: 'PUT', url: QDRANT + '/collections/' + COLL + '/points', body: { points }, json: true, timeout: 30000 });
  return [{ json: { _indexed: points.length } }];
} catch (e) {
  return [{ json: { _indexed: 0, _index_error: String(e && e.message || e) } }];
}

const items = $input.all();
if (!items.length) return [];
const ts = new Date().toISOString();
const MAP = { remotive:'Remotive', jobicy:'Jobicy', weworkremotely:'WWR', wwr:'WWR', 'francetravail':'France Travail', 'pole-emploi':'France Travail', himalayas:'Himalayas', themuse:'The Muse', 'themuse.com':'The Muse', remoteok:'RemoteOK' };
function guess(msg){ const m=String(msg||'').toLowerCase(); for (const k in MAP) if (m.includes(k)) return MAP[k]; return 'unknown'; }
const failures = items.map(it => {
  const e = (it.json && it.json.error) || it.json || {};
  const msg = e.message || e.description || (typeof e==='string'?e:JSON.stringify(e).slice(0,300));
  return { source: guess(msg), message: String(msg).slice(0,300) };
});
const record = { ts, level:'warn', workflow: $workflow.name, exec: $execution.id, event:'source_fetch_failed', failed_count: failures.length, failures };
const stamp = ts.replace(/[:.]/g,'-').slice(0,19);
const filePath = $env.VEILLE_OUTPUT_DIR + '/_errors/sources_' + stamp + '.json';
const base64 = Buffer.from(JSON.stringify(record, null, 2), 'utf-8').toString('base64');
return [{ json: { filePath, ...record }, binary: { data: { data: base64, mimeType:'application/json', fileName:'sources_'+stamp+'.json', fileExtension:'json' } } }];
